     1→<!DOCTYPE html>
     2→<html lang="ko">
     3→<head>
     4→  <meta charset="UTF-8">
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→  <title>공학용 계산기</title>
     7→  <style>
     8→    * {
     9→      margin: 0;
    10→      padding: 0;
    11→      box-sizing: border-box;
    12→    }
    13→
    14→    body {
    15→      display: flex;
    16→      justify-content: center;
    17→      align-items: center;
    18→      min-height: 100vh;
    19→      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    20→      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    21→    }
    22→
    23→    .calculator {
    24→      background: white;
    25→      border-radius: 10px;
    26→      box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
    27→      width: 420px;
    28→      padding: 20px;
    29→    }
    30→
    31→    .display {
    32→      background: #2d3436;
    33→      color: #00ff00;
    34→      font-size: 2.5em;
    35→      padding: 20px;
    36→      border-radius: 5px;
    37→      text-align: right;
    38→      margin-bottom: 20px;
    39→      min-height: 60px;
    40→      word-wrap: break-word;
    41→      word-break: break-all;
    42→      font-family: 'Courier New', monospace;
    43→    }
    44→
    45→    .buttons {
    46→      display: grid;
    47→      grid-template-columns: repeat(5, 1fr);
    48→      gap: 8px;
    49→    }
    50→
    51→    button {
    52→      padding: 15px;
    53→      font-size: 1.1em;
    54→      border: none;
    55→      border-radius: 5px;
    56→      cursor: pointer;
    57→      font-weight: bold;
    58→      transition: all 0.2s;
    59→    }
    60→
    61→    button:active {
    62→      transform: scale(0.95);
    63→    }
    64→
    65→    .number {
    66→      background: #ecf0f1;
    67→      color: #2d3436;
    68→    }
    69→
    70→    .number:hover {
    71→      background: #bdc3c7;
    72→    }
    73→
    74→    .operator {
    75→      background: #667eea;
    76→      color: white;
    77→    }
    78→
    79→    .operator:hover {
    80→      background: #5568d3;
    81→    }
    82→
    83→    .equals {
    84→      background: #27ae60;
    85→      color: white;
    86→      grid-column: span 2;
    87→    }
    88→
    89→    .equals:hover {
    90→      background: #229954;
    91→    }
    92→
    93→    .clear {
    94→      background: #e74c3c;
    95→      color: white;
    96→    }
    97→
    98→    .clear:hover {
    99→      background: #c0392b;
   100→    }
   101→
   102→    .function {
   103→      background: #f39c12;
   104→      color: white;
   105→    }
   106→
   107→    .function:hover {
   108→      background: #d68910;
   109→    }
   110→
   111→    .equals {
   112→      grid-column: span 2;
   113→    }
   114→  </style>
   115→</head>
   116→<body>
   117→  <div class="calculator">
   118→    <div class="display" id="display">0</div>
   119→    <div class="buttons">
   120→      <button class="function" onclick="scientificFunc('log')">log</button>
   121→      <button class="function" onclick="scientificFunc('ln')">ln</button>
   122→      <button class="function" onclick="scientificFunc('sqrt')">√</button>
   123→      <button class="function" onclick="scientificFunc('square')">x²</button>
   124→      <button class="clear" onclick="clearDisplay()">C</button>
   125→
   126→      <button class="function" onclick="appendNumber(Math.PI.toFixed(5))">π</button>
   127→      <button class="operator" onclick="appendOperator('/')">÷</button>
   128→      <button class="operator" onclick="appendOperator('*')">×</button>
   129→      <button class="operator" onclick="appendOperator('-')">−</button>
   130→      <button class="operator" onclick="appendOperator('+')">+</button>
   131→
   132→      <button class="number" onclick="appendNumber('7')">7</button>
   133→      <button class="number" onclick="appendNumber('8')">8</button>
   134→      <button class="number" onclick="appendNumber('9')">9</button>
   135→      <button class="function" onclick="scientificFunc('reciprocal')">1/x</button>
   136→      <button class="function" onclick="scientificFunc('pow10')">10ˣ</button>
   137→
   138→      <button class="number" onclick="appendNumber('4')">4</button>
   139→      <button class="number" onclick="appendNumber('5')">5</button>
   140→      <button class="number" onclick="appendNumber('6')">6</button>
   141→      <button class="function" onclick="scientificFunc('factorial')">n!</button>
   142→      <button class="number" onclick="appendNumber('.')">.</button>
   143→
   144→      <button class="number" onclick="appendNumber('1')">1</button>
   145→      <button class="number" onclick="appendNumber('2')">2</button>
   146→      <button class="number" onclick="appendNumber('3')">3</button>
   147→      <button class="function" onclick="scientificFunc('percent')">%</button>
   148→      <button class="equals" onclick="calculate()" style="grid-row: span 2;">
   149→        =
   150→      </button>
   151→
   152→      <button class="number" onclick="appendNumber('0')" style="grid-column: span 2;">0</button>
   153→    </div>
   154→  </div>
   155→
   156→  <script>
   157→    let display = document.getElementById('display');
   158→    let currentValue = '0';
   159→    let previousValue = '';
   160→    let operation = null;
   161→    let shouldResetDisplay = false;
   162→
   163→    function updateDisplay() {
   164→      display.textContent = currentValue;
   165→    }
   166→
   167→    function appendNumber(num) {
   168→      if (shouldResetDisplay) {
   169→        currentValue = num;
   170→        shouldResetDisplay = false;
   171→      } else {
   172→        if (currentValue === '0' && num !== '.') {
   173→          currentValue = num;
   174→        } else if (num === '.' && currentValue.includes('.')) {
   175→          return;
   176→        } else {
   177→          currentValue += num;
   178→        }
   179→      }
   180→      updateDisplay();
   181→    }
   182→
   183→    function appendOperator(op) {
   184→      if (operation !== null) {
   185→        calculate();
   186→      }
   187→      previousValue = currentValue;
   188→      operation = op;
   189→      shouldResetDisplay = true;
   190→    }
   191→
   192→    function calculate() {
   193→      if (operation === null || shouldResetDisplay) return;
   194→
   195→      const prev = parseFloat(previousValue);
   196→      const current = parseFloat(currentValue);
   197→      let result;
   198→
   199→      switch (operation) {
   200→        case '+':
   201→          result = prev + current;
   202→          break;
   203→        case '-':
   204→          result = prev - current;
   205→          break;
   206→        case '*':
   207→          result = prev * current;
   208→          break;
   209→        case '/':
   210→          result = current !== 0 ? prev / current : 0;
   211→          break;
   212→        default:
   213→          return;
   214→      }
   215→
   216→      currentValue = String(result);
   217→      operation = null;
   218→      shouldResetDisplay = true;
   219→      updateDisplay();
   220→    }
   221→
   222→    function clearDisplay() {
   223→      currentValue = '0';
   224→      previousValue = '';
   225→      operation = null;
   226→      shouldResetDisplay = false;
   227→      updateDisplay();
   228→    }
   229→
   230→    function scientificFunc(func) {
   231→      const value = parseFloat(currentValue);
   232→      let result;
   233→
   234→      switch (func) {
   235→        case 'log':
   236→          result = value > 0 ? Math.log10(value) : 'Error';
   237→          break;
   238→        case 'ln':
   239→          result = value > 0 ? Math.log(value) : 'Error';
   240→          break;
   241→        case 'sqrt':
   242→          result = value >= 0 ? Math.sqrt(value) : 'Error';
   243→          break;
   244→        case 'square':
   245→          result = value * value;
   246→          break;
   247→        case 'reciprocal':
   248→          result = value !== 0 ? 1 / value : 'Error';
   249→          break;
   250→        case 'pow10':
   251→          result = Math.pow(10, value);
   252→          break;
   253→        case 'factorial':
   254→          result = factorial(Math.floor(value));
   255→          break;
   256→        case 'percent':
   257→          result = value / 100;
   258→          break;
   259→        default:
   260→          return;
   261→      }
   262→
   263→      currentValue = String(result);
   264→      shouldResetDisplay = true;
   265→      updateDisplay();
   266→    }
   267→
   268→    function factorial(n) {
   269→      if (n < 0) return 'Error';
   270→      if (n === 0 || n === 1) return 1;
   271→      let result = 1;
   272→      for (let i = 2; i <= n; i++) {
   273→        result *= i;
   274→      }
   275→      return result;
   276→    }
   277→
   278→    updateDisplay();
   279→  </script>
   280→</body>
   281→</html>
